import React, { useState } from "react";
import './Logout.css';
import './Welcome';
import { useLocation, useNavigate } from "react-router";
import axios from "axios";
function Logout () {
    const [data, setData] = useState([]); 
    const location = useLocation();
    const navigate = useNavigate();
    const getCall = (userName) => {
        axios.get(`http://localhost:8080/user/${userName}/items`).then(data => setData(data))
        return data;
        console.log(data)
        }
    return <div className="nav-bar">
    <div className="header">
    <a href="#default" className="logo">Productiv</a>
    <div className="header-right">
    <a href="#home">My Account</a>
    <a href="#contact" onClick={() => navigate('/')} >Logout</a>
    <button onClick={() => getCall('userName')}></button>
  </div>
    </div>
    </div>
}

export default Logout;
